import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Box, Container, Button, Flex, Text, Section, Heading} from "@radix-ui/themes";
import './App.css';
import {
  blue,
	blueDark,
} from "@radix-ui/colors";

// Create your theme
const theme = {
	colors: {
		...gray,
		...blue,
		...red,
		...green,
	},
};

// Create your dark theme
const darkTheme = {
	colors: {
		...blueDark,
	},
};


function App() {
  return (
    <Theme theme={theme} appearance="dark">
      <ThemePanel />
      <Container size="4">
        <Section>
          <Flex gap="4" direction="column">
            <Heading mt="5" size="9">Hey, I'm Ted</Heading>
            <Heading weight="medium" size="6">Full Stack Web Developer</Heading>
            <Heading className="my_promise" weight="light" size="4">I create custom, scalable software to help companies thrive on the web.</Heading>
          </Flex>
          <Flex gap="4" direction="column">
            {/* <Button size="3" variant="outline">Get in touch</Button>
            <Button size="3" variant="soft">View my work</Button> */}
          </Flex>
        </Section>
      </Container>
    </Theme>
  );
}

export default App;
